export default function WriterBadgeIcon({ width = 120, height, color = "#70c2ea", style, ...props }) {
  const computedHeight = height ?? (width * WRITER_BADGE_HEIGHT) / WRITER_BADGE_WIDTH;

  return (
    <Svg
      width={width}
      height={computedHeight}
      viewBox={`0 0 ${WRITER_BADGE_WIDTH} ${WRITER_BADGE_HEIGHT}`}
      fill="none"
      accessibilityRole="image"
      accessible
      style={style}
      {...props}
    >
      {WRITER_BADGE_LAYERS.map((layer, index) => (
        <Path key={index} d={layer.d} fill={color} fillOpacity={layer.opacity} />
      ))}
    </Svg>
  );
}
